query.sparql:
SELECT ?animal WHERE {
  wd:Q625657 wdt:P7779 ?militaryUnit.
  ?militaryUnit wdt:P798 ?militaryDesignation.
  ?militaryUnit wdt:P3156 ?operation.
  ?operation wdt:P4624 ?animal.
}

SELECT ?character WHERE {
  ?character wdt:P451 wd:Q4205826 .
  ?character wdt:P451 wd:Q4463198 .
}

SELECT ?tencent ?npc ?founder ?founderLabel ?p WHERE {
  ?tencent wdt:P31 wd:Q4830453.  # Tencent as a company
  ?npc wdt:P31 wd:Q13218629.     # National People's Congress
  ?tencent ?p ?founder.           # Any property for founders of Tencent
  FILTER(?p IN (wdt:P112, wdt:P749)) # Checking common properties for founders
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}
